	 (3543,563,'P. Süda',NULL,1,1897,1907,'Käsikirjale on märgitud: "1897 a. ümber." Süda: "Pärnu köstri A. Jungi üleskirjutatud 25 viisi kirjutasin temalt  -- oma tänavu aastase korjanduse hulka üles." (lk 1873) " -- Pärnu köster (praegu Tartus üliõpilane) -- Pilistvere kihelkonnast üleskirjutanud" (lk 1866). See laul on siiski Virumaalt. A. Jungi eluaastad 1877-1959, Pärnu köster oli ta 1900-1907 (Viki). [T. S.]'),
	 (3543,1214,'A. Jung',NULL,1,1897,1907,'Käsikirjale on märgitud: "1897 a. ümber." Süda: "Pärnu köstri A. Jungi üleskirjutatud 25 viisi kirjutasin temalt  -- oma tänavu aastase korjanduse hulka üles." (lk 1873) " -- Pärnu köster (praegu Tartus üliõpilane) -- Pilistvere kihelkonnast üleskirjutanud" (lk 1866). See laul on siiski Virumaalt. A. Jungi eluaastad 1877-1959, Pärnu köster oli ta 1900-1907 (Viki). [T. S.]'),
	 (3543,NULL,NULL,NULL,4,1897,1907,'Ka lk 1870 on üks Virumaa laul, seal koos esitaja nimega Elisab. Jung, 50-a. Lüganuselt, kes võis olla ka selle teise Virumaa laulu teadja. Arturi ema nimi on Katerina Elisabeth Jung (Riis), seega võis olla tema ema. (Viki). T. S.'),
