	 (4352,637,NULL,NULL,5,2021,NULL,'Esitaja: "Noorõst ol´ heli hüä, laulõss nii et mõts kumass." Laulmise kohta: "ütelda".'),
	 (4360,637,NULL,NULL,5,2021,NULL,'Taive: 9 silpi värsis, teine värss lühendatud lõpuga.'),
	 (4361,637,NULL,NULL,5,2021,NULL,'Taive: 9 silpi värsis, teine värss lühendatud lõpuga. Heliulatus on ellöökide võrra suurem.]'),
	 (4362,637,NULL,NULL,5,2021,NULL,'Taive: 9 silpi värsis, teine värss lühendatud lõpuga. Helisalvestusel kostavad pikendused pea igal 2. seilbil, v.a. sõnades "sööks-nu" ja "meeli".'),
	 (4363,637,NULL,NULL,5,2021,NULL,'Taive: 9 silpi värsis, teine värss lühendatud lõpuga; vahepeal lisasilpi ei ole.'),
	 (4373,637,NULL,NULL,5,2021,NULL,'Tegelikus struktuuris ei kordu terve esimene värsipool X, vaid selle esimene 2-silbiline sõna kordub (vt teksti). Selle jaoks ei ole praegu eraldi vormiskeemi. Helirida gis a h c'),
	 (4380,637,NULL,NULL,5,2021,NULL,'Tekstikoguja: Alatskivi viis Nr 80, do. (lk 405).'),
	 (4392,637,NULL,NULL,5,2021,NULL,'Esituse kirjeldus.'),
	 (4399,637,NULL,NULL,5,2021,NULL,'[teksti juures märge: vt viis nr 165.!?]'),
	 (4400,637,NULL,NULL,5,2021,NULL,'[teksti juures märge: vt viis nr 165.!?]'),
	 (4403,637,NULL,NULL,5,2021,NULL,'Viis ja tekst on noodis imelikult teineteise alla kirjutatud. T. S.'),
	 (4404,637,NULL,NULL,5,2021,NULL,'Koguja: "ette laulnud"'),
	 (4409,637,NULL,NULL,5,2021,NULL,'Viisi juures märge "moderato"'),
	 (4411,637,NULL,NULL,5,2021,NULL,'Noodi juures on viited 8 tekstile, kõigi esiread on noodi alla kirjutatud.'),
	 (4413,637,NULL,NULL,5,2021,NULL,'Laulu lõpus on veel muid värsse. T.'),
	 (4416,637,NULL,NULL,5,2021,NULL,'Viisi juures märge "moderato"'),
	 (4421,637,NULL,NULL,5,2021,NULL,'Teksti juures on vana fonogramminumber, neid on hiljem muudetud.'),
	 (4423,637,NULL,NULL,5,2021,NULL,'"Ranna laul."'),
	 (4424,637,NULL,NULL,5,2021,NULL,'"Viis Nr 3 ja t Nr 93". Viisidel on topelt numbrid, seega mõeldakse viisi EÜS VI 884 (52/3).'),
	 (4427,637,NULL,NULL,5,2021,NULL,'"Nr 29a-s tuleb palju rütmilisi teisendusi kui intervallisi." (lk 2492)'),
	 (4430,637,NULL,NULL,5,2021,NULL,'"Mittepikka". [Pl vt. pulmalaulud (EÜS XI 821/2 (12)) E.T.]'),
	 (4440,637,NULL,NULL,5,2021,NULL,'"Viis Nr 3 ja t Nr 93". Viisidel on topelt numbrid, seega mõeldakse viisi EÜS VI 884 (52/3).'),
	 (4450,637,NULL,NULL,5,2021,NULL,'Esitusel kaldub rõhutu pos pikenema, sarnaselt rütmitüübile 4'),
	 (4452,637,NULL,NULL,5,2021,NULL,'Kordamööda mitu naist proovib, arutatakse. [T. S.]'),
	 (4456,637,NULL,NULL,5,2021,NULL,'Taive: 9 silpi värsis, teine värss lühendatud lõpuga.'),
	 (4460,637,NULL,NULL,5,2021,NULL,'Võis laulda koos või üksinda. [Esitaja jutust kokkuvõte, T. S.]'),
	 (4468,637,NULL,NULL,5,2021,NULL,'Sama teksti juures on ka teine, refrääniga viis.'),
	 (4469,637,NULL,NULL,5,2021,NULL,'Taive: Rütmitüüp 1A on seotud ilmselt konkreetse teksti värisehitusega, sellepärast ei märkinud ma seda sama viisi teistes variantides.'),
	 (4470,637,NULL,NULL,5,2021,NULL,'Noodi all teine tekst (EÜS IX 1175 (163))'),
	 (4471,637,NULL,NULL,5,2021,NULL,'Edna märkus: [rütm punkteeritud, v.a viimane silpnoodi paar. Kas äkki on niiviisi kirjeldanid rõhku ja rütm on ikkagi 1.? Sisestaja pannud 4A! E.T.] Edna on pannud siia rütmitüübi 1. Nii või naa, kui esitaja rõhutamise tõttu pikendab, siis tekib pikendus. Vrdl ERA III 1, 52 (95)'),
	 (4472,637,NULL,NULL,5,2021,NULL,'Liikuv, uuema ilmega viis. Tedrel sellist laulutüüpi pole.'),
	 (4478,637,NULL,NULL,5,2021,NULL,'Viisi vorm: 1/2+1/2+1/2+1/2. Stroofis tähistavad X ja Y poolvärssi, k2 viisirea jooksul lauldakse teksti ühe värsi jagu. [T. S.]'),
	 (4492,637,NULL,NULL,5,2021,NULL,'Viis on täpselt Hendrik Jantsoni pulmalauluviis, ERA, Pl. 98 A1–3. T. S.'),
	 (4493,637,NULL,NULL,5,2021,NULL,'Viisi juures: "Vaata nr 28". See on samuti pulmalauluviis. Vt teksti EÜS IV 1883/937 (2) - koguja nimetab selle jaoks viise nr 7, 28, 58, 59, 62 - ilmselt peab neid kõiki tekstile sobivaks. T. S.'),
	 (4494,637,NULL,NULL,5,2021,NULL,'Koguja: "Ilma sõnadeta."'),
	 (4496,637,NULL,NULL,5,2021,NULL,'Viis olevat EÜS IV 1861 (58) "teisend". [T. S.]'),
	 (4497,637,NULL,NULL,5,2021,NULL,'Viisikoguja järgi: Pärnumaal kuuldud eesti viis. Laulja nimetas teda regivärsiks. (Sõnu ei mäleta).'),
	 (4498,637,NULL,NULL,5,2021,NULL,'Nüüd on läinud kogujad lahku, viisikoguja on Amblas ja leiab vaestemajast laulueide, kelle laule ta pärast ümber ei kirjuta kogusse. Seejärel Ambla lähedal laulab neile tislerieit, "spetsialist kiige laulude jaoks" - see ehk ei laulnud 2-realisi regiviise? (lk 2215). Andmed EÜS VII 2261/5.'),
	 (4499,637,NULL,NULL,5,2021,NULL,'Ühine pealkiri: Vanarahva ilmalikude laulude viisid. Sõnade kordajad'),
	 (4502,637,NULL,NULL,5,2021,NULL,'Käsitsi tõmmatud noodijooned.'),
	 (4508,637,NULL,NULL,5,2021,NULL,'Esituse kirjeldus.'),
	 (4509,637,NULL,NULL,5,2021,NULL,'Esituse kirjeldus.'),
	 (4510,637,NULL,NULL,5,2021,NULL,'"snd., kasv. ja elanud Kurivere külas Vodja mõisa juures, Peetri khk.; sääl ka laulud õppinud V. mõisa moonakatemajas." (viis)'),
	 (4514,637,NULL,NULL,5,2021,NULL,'"Laulnud" (tekst)'),
	 (4515,637,NULL,NULL,5,2021,NULL,'"Laulnud" (tekst). Noodi all teine tekst. Üks värss kirjutatud noodi EÜS VI 903 (130) alla.'),
	 (4517,637,NULL,NULL,5,2021,NULL,'"Laulnud" (tekst). Noodi all teine tekst. Üks värss, kirjutatud noodi EÜS VI 903 (130) alla.'),
	 (4518,637,NULL,NULL,5,2021,NULL,'"Laulnud" (tekst). Noodi all teine tekst. Üks värss, kirjutatud noodi EÜS VI 903 (130) alla.'),
	 (4519,637,NULL,NULL,5,2021,NULL,'"Laulnud" (tekst). Noodi all teine tekst. Üks värss, kirjutatud noodi EÜS VI 903 (130) alla.'),
	 (4520,637,NULL,NULL,5,2021,NULL,'Esituse kirjeldus.'),
	 (4521,637,NULL,NULL,5,2021,NULL,'Noodi all teine tekst. "Vastu laulnud" - Nr 257 peale. [T. S.]'),
	 (4524,637,NULL,NULL,5,2021,NULL,'"laulnud" (tekst). Taive: Rütmis jagunevad 3 esimest värsijalga trioolideks. Viisi juurde On märgitud tekstide numbrid 49, 50. Viimane käib arvatavasti järgmise viisi kohta, kus teksti nr puudub.'),
	 (4529,637,NULL,NULL,5,2021,NULL,'Koguja kirjeldab viiside ja tekstide vaba kombineerimist ja detoneerivat laulmist (lk 505). T. S.'),
	 (4533,637,NULL,NULL,5,2021,NULL,'"snd., kasv. ja elanud Kurivere külas Vodja mõisa juures, Peetri khk.; sääl ka laulud õppinud V. mõisa moonakatemajas." (viis)'),
	 (4534,637,NULL,NULL,5,2021,NULL,'NB! 4-realine viis. Vt märkust viisi järel. E.T. Noot ilma tekstita, viisikoguja märkus: "laul nr. 37 [sõnad]. Laulu sõnad hra. Rosenstrauchi käes. Laulnud ---" Tekstikoguja: "L"=lauldud. T. S.'),
	 (4535,637,NULL,NULL,5,2021,NULL,'Viisikoguja: "laul nr. 38 [sõnad]. Laulnud --" Noodi all teksti ei ole, teksti nr. 38 algusvärss on viisi pealkirjaks. Tekstikogus on märge "L"=lauldud. T. S.'),
	 (4537,637,NULL,NULL,5,2021,NULL,'Koguja kirjeldab viiside ja tekstide vaba kombineerimist ja detoneerivat laulmist (lk 505). T. S.'),
	 (4550,637,NULL,NULL,5,2021,NULL,'"Viis Nr 3 ja t Nr 92". Viisidel on topelt numbrid, seega mõeldakse viisi EÜS VI 884 (52/3).'),
	 (4551,637,NULL,NULL,5,2021,NULL,'"Viis Nr 3 ja t Nr 92". Viisidel on topelt numbrid, seega mõeldakse viisi EÜS VI 884 (52/3).'),
	 (4552,637,NULL,NULL,5,2021,NULL,'"Viis Nr 3 ja t Nr 92". Viisidel on topelt numbrid, seega mõeldakse viisi EÜS VI 884 (52/3).'),
	 (4554,637,NULL,NULL,5,2021,NULL,'Noodi all teine tekst. "Laulnud" (tekst). Üks värss kirjutatud noodi EÜS VI 903 (130) alla'),
	 (4556,637,NULL,NULL,5,2021,NULL,'Noodi all teine tekst (EÜS IX 1175 (163))'),
	 (4558,637,NULL,NULL,5,2021,NULL,'Koguja märkus: Viis 17/3 on õieti 16/2 variant. Taive: Noodi all on märgitud teksti algus: "Laksu, laksu, laekene" ja viis nr 36. Viis nr 36 ei alga nende sõnadega. Tekstid algussõnadega "Laksu, laksu laekene" on üles kirjutatud EÜS VI 1197/8 (128) Anna Konsa; EÜS X 2887 (25) Mari Konsa käest; tegin sellest eraldi kirje.'),
	 (4559,637,NULL,NULL,5,2021,NULL,'Koguja märkus: Viis 17/3 on õieti 16/2 variant.');
