	 (4538,1,NULL,NULL,NULL,NULL),
	 (4539,1,NULL,NULL,NULL,'"Üleüldiselt tuleb tähendada laulude kiiruse kohta, et kõik laulikud ühesuguses tempos laulsivad, s.o., missuguses, nagu esimese laulu ette laulsivad; ainult mõni üksik laul, (nagu näit. Simson´i lauldud ja m. t.) sai kas vähe pikemalt, ehk vähe ruttemalt ette toodud." (lk 759)'),
	 (4540,1,NULL,NULL,NULL,'"Üleüldiselt tuleb tähendada laulude kiiruse kohta, et kõik laulikud ühesuguses tempos laulsivad, s.o., missuguses, nagu esimese laulu ette laulsivad; ainult mõni üksik laul, (nagu näit. Simson´i lauldud ja m. t.) sai kas vähe pikemalt, ehk vähe ruttemalt ette toodud." (lk 759)'),
	 (4541,1,NULL,NULL,NULL,NULL),
	 (4542,1,NULL,NULL,NULL,NULL),
	 (4547,1,NULL,NULL,NULL,'"Kõik laulud saivad ühe viisi pääl lauldud, ---"'),
	 (4548,1,NULL,NULL,NULL,'"laulnud" (teksti juures).'),
	 (4549,1,NULL,NULL,NULL,NULL),
	 (4550,1,NULL,NULL,NULL,'"Laulnud" (teksti juures). "Viis 52/3 sai lauldud, nagu a ja b all ülestähendatud ja siingi märkide + kohal vahel nii, vahel teisiti lauldud." (viisi juures)'),
	 (4551,1,NULL,NULL,NULL,'"Laulnud" (teksti juures). "Viis 52/3 sai lauldud, nagu a ja b all ülestähendatud ja siingi märkide + kohal vahel nii, vahel teisiti lauldud." (viisi juures)'),
	 (4552,1,NULL,NULL,NULL,'"Laulnud" (teksti juures). "Viis 52/3 sai lauldud, nagu a ja b all ülestähendatud ja siingi märkide + kohal vahel nii, vahel teisiti lauldud." (viisi juures)'),
	 (4553,1,NULL,NULL,NULL,'"laulnud" (teksti juures).'),
	 (4554,1,NULL,NULL,NULL,NULL),
	 (4555,1,NULL,NULL,NULL,'Märkus algkõrguse kohta: "Lauldi okt. m." = oktav madalamalt (noot).'),
	 (4556,1,NULL,NULL,NULL,'Tekstikoguja märgib: "ettelugenud", viisikoguja: "ettelaulja"'),
	 (4557,1,NULL,NULL,NULL,'Märkus algkõrguse kohta: "Lauldi okt. m." = oktav madalamalt (noot).'),
	 (4558,1,NULL,NULL,NULL,'"Sepp kiidab ennast (pulmas)". (lk 928). 5. värsi juures: "Vastu".'),
	 (4559,1,NULL,NULL,NULL,NULL);
